package com.hospital.management.model;import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.Objects;/** An offline payment record containing no private payment credentials. */public class Payment{private Long paymentId,billId,receivedBy;private String paymentNumber,paymentMethod,transactionReference,status,receivedByUsername,billNumber,patientName;private LocalDateTime paymentDate,createdAt;private BigDecimal amount;public Long getPaymentId(){return paymentId;}public void setPaymentId(Long v){paymentId=v;}public String getPaymentNumber(){return paymentNumber;}public void setPaymentNumber(String v){paymentNumber=v;}public Long getBillId(){return billId;}public void setBillId(Long v){billId=v;}public LocalDateTime getPaymentDate(){return paymentDate;}public void setPaymentDate(LocalDateTime v){paymentDate=v;}public BigDecimal getAmount(){return amount;}public void setAmount(BigDecimal v){amount=v;}public String getPaymentMethod(){return paymentMethod;}public void setPaymentMethod(String v){paymentMethod=v;}public String getTransactionReference(){return transactionReference;}public void setTransactionReference(String v){transactionReference=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public Long getReceivedBy(){return receivedBy;}public void setReceivedBy(Long v){receivedBy=v;}public String getReceivedByUsername(){return receivedByUsername;}public void setReceivedByUsername(String v){receivedByUsername=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public String getBillNumber(){return billNumber;}public void setBillNumber(String v){billNumber=v;}public String getPatientName(){return patientName;}public void setPatientName(String v){patientName=v;}public boolean equals(Object o){return this==o||(o instanceof Payment p&&paymentId!=null&&paymentId.equals(p.paymentId));}public int hashCode(){return Objects.hashCode(paymentId);}public String toString(){return"Payment{id="+paymentId+", number="+paymentNumber+", status="+status+"}";}}
